+async function runRescue(params: {
+  commandBody: string;
+  cfg: OpenClawConfig;
+  ctx?: CommandContext;
+}) {
+  const ctx = params.ctx ?? commandContext();
+  return await runCrestodianRescueMessage({
+    cfg: params.cfg,
+    command: { ...ctx, commandBodyNormalized: params.commandBody },
+    commandBody: params.commandBody,
+    isGroup: false,
+  });
+}
